import { IMessageComposer } from '@nitrots/nitro-renderer';

export class SellItemComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(itemId: number, quantity: number) {
        this._data = [itemId, quantity];
        console.log('[📦] SellItemComposer sent →', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
